class Solution:
    def maxEqualFreq(self, nums):
        from collections import Counter
        best = 0
        cnt = Counter()
        for i, v in enumerate(nums):
            cnt[v] += 1
            freqs = list(cnt.values())
            for j in range(len(freqs)):
                trial = freqs[:j] + [freqs[j] - 1] + freqs[j + 1:]
                trial = [f for f in trial if f > 0]
                if not trial or len(set(trial)) == 1:
                    best = i + 1
                    break
        return best

