class Solution:
    def maxEqualFreq(self, nums):
        from collections import defaultdict
        count = defaultdict(int)
        freq = defaultdict(int)
        best = 0
        for i, v in enumerate(nums):
            c = count[v]
            if c > 0:
                freq[c] -= 1
                if freq[c] == 0:
                    del freq[c]
            count[v] = c + 1
            freq[c + 1] += 1
            length = i + 1
            ok = False
            if len(freq) == 1:
                k = next(iter(freq))
                if k == 1 or freq[k] == 1:
                    ok = True
            elif len(freq) == 2:
                k1, k2 = sorted(freq)
                if k1 == 1 and freq[k1] == 1:
                    ok = True
                elif k2 == k1 + 1 and freq[k2] == 1:
                    ok = True
            if ok:
                best = length
        return best

