var maxEqualFreq = function(nums) {
    const count = new Map();
    const freq = new Map();
    let best = 0;
    for (let i = 0; i < nums.length; i++) {
        const v = nums[i];
        const c = count.get(v) || 0;
        if (c > 0) {
            freq.set(c, freq.get(c) - 1);
            if (freq.get(c) === 0) freq.delete(c);
        }
        count.set(v, c + 1);
        freq.set(c + 1, (freq.get(c + 1) || 0) + 1);
        let ok = false;
        if (freq.size === 1) {
            const k = freq.keys().next().value;
            if (k === 1 || freq.get(k) === 1) ok = true;
        } else if (freq.size === 2) {
            const keys = [...freq.keys()].sort((a, b) => a - b);
            const [k1, k2] = keys;
            if (k1 === 1 && freq.get(k1) === 1) ok = true;
            else if (k2 === k1 + 1 && freq.get(k2) === 1) ok = true;
        }
        if (ok) best = i + 1;
    }
    return best;
};
